INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Single-Leg_Leg_Extension','Single-Leg Leg Extension','cuádriceps',ARRAY[]::text[],'máquina','strength',ARRAY['Seat yourself in the machine and adjust it so that you are positioned properly. The pad should be against the lower part of the shin but not in contact with the ankle. Adjust the seat so that the pivot point is in line with your knee. Select a weight appropriate for your abilities.','Maintaining good posture, fully extend one leg, pausing at the top of the motion.','Return to the starting position without letting the weight stop, keeping tension on the muscle.','Repeat for the desired number of repetitions.'],'Seat yourself in the machine and adjust it so that you are positioned properly. The pad should be against the lower part of the shin but not in contact with the ankle. Adjust the seat so that the pivot point is in line with your knee. Select a weight appropriate for your abilities. Maintaining good posture, fully extend one leg, pausing at the top of the motion. Return to the starting position without letting the weight stop, keeping tension on the muscle. Repeat for the desired number of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Single-Leg_Leg_Extension/0.jpg','exercisedb',true),('Single-Leg_Stride_Jump','Single-Leg Stride Jump','cuádriceps',ARRAY['abductores','aductores','pantorrillas','isquiotibiales'],'otro','plyometrics',ARRAY['Stand to the side of a box with your inside foot on top of it, close to the edge.','Begin by swinging the arms upward as you push through the top leg, jumping upward as high as possible. Attempt to drive the opposite knee upward.','Land in the same position that you started, using your inside leg to decelerate the impact.'],'Stand to the side of a box with your inside foot on top of it, close to the edge. Begin by swinging the arms upward as you push through the top leg, jumping upward as high as possible. Attempt to drive the opposite knee upward. Land in the same position that you started, using your inside leg to decelerate the impact.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Single-Leg_Stride_Jump/0.jpg','exercisedb',true),('Single_Dumbbell_Raise','Single Dumbbell Raise','hombros',ARRAY['antebrazos','trapecios'],'mancuernas','strength',ARRAY['With a wide stance, hold a dumbell with both hands, grasping the head of the dumbbell instead of the handle. Your arms should be extended and hanging at the waist. This will be your starting position.','Raise the weight until it is above shoulder level, keeping your arms extended. Your torso and hips should remain stationary throughout the movement.','Return to the starting position and repeat for the recommended amount of repetitions.'],'With a wide stance, hold a dumbell with both hands, grasping the head of the dumbbell instead of the handle. Your arms should be extended and hanging at the waist. This will be your starting position. Raise the weight until it is above shoulder level, keeping your arms extended. Your torso and hips should remain stationary throughout the movement. Return to the starting position and repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Single_Dumbbell_Raise/0.jpg','exercisedb',true),('Single_Leg_Butt_Kick','Single Leg Butt Kick','cuádriceps',ARRAY['pantorrillas','isquiotibiales'],'peso corporal','plyometrics',ARRAY['Begin by standing on one leg, with the bent knee raised. This will be your start position.','Using a countermovement jump, take off upward by extending the hip, knee, and ankle of the grounded leg.','Immediately flex the knee and attempt to touch your butt with the heel of your jumping leg.','Return the leg to a partially bent position underneath the hips and land. Your opposite leg should stay in relatively the same position throughout the drill.'],'Begin by standing on one leg, with the bent knee raised. This will be your start position. Using a countermovement jump, take off upward by extending the hip, knee, and ankle of the grounded leg. Immediately flex the knee and attempt to touch your butt with the heel of your jumping leg. Return the leg to a partially bent position underneath the hips and land. Your opposite leg should stay in relatively the same position throughout the drill.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Single_Leg_Butt_Kick/0.jpg','exercisedb',true),('Single_Leg_Glute_Bridge','Single Leg Glute Bridge','glúteos',ARRAY['isquiotibiales'],'peso corporal','strength',ARRAY['Lay on the floor with your feet flat and knees bent.','Raise one leg off of the ground, pulling the knee to your chest. This will be your starting position.','Execute the movement by driving through the heel, extending your hip upward and raising your glutes off of the ground.','Extend as far as possible, pause and then return to the starting position.'],'Lay on the floor with your feet flat and knees bent. Raise one leg off of the ground, pulling the knee to your chest. This will be your starting position. Execute the movement by driving through the heel, extending your hip upward and raising your glutes off of the ground. Extend as far as possible, pause and then return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Single_Leg_Glute_Bridge/0.jpg','exercisedb',true),('Single_Leg_Push-off','Single Leg Push-off','cuádriceps',ARRAY['pantorrillas','isquiotibiales'],'otro','plyometrics',ARRAY['Stand on the ground with one foot resting on the box, heel close to the edge.','Push off with your foot on top of the box, trying to gain as much height as possible by extending through the hip and knee.','Land with the same foot on top of the box, returning your other foot back to the start position.'],'Stand on the ground with one foot resting on the box, heel close to the edge. Push off with your foot on top of the box, trying to gain as much height as possible by extending through the hip and knee. Land with the same foot on top of the box, returning your other foot back to the start position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Single_Leg_Push-off/0.jpg','exercisedb',true),('Sit-Up','Sit-Up','abdominales',ARRAY[]::text[],'peso corporal','strength',ARRAY['Lie down on the floor placing your feet either under something that will not move or by having a partner hold them. Your legs should be bent at the knees.','Place your hands behind your head and lock them together by clasping your fingers. This is the starting position.','Elevate your upper body so that it creates an imaginary V-shape with your thighs. Breathe out when performing this part of the exercise.','Once you feel the contraction for a second, lower your upper body back down to the starting position while inhaling.','Repeat for the recommended amount of repetitions.'],'Lie down on the floor placing your feet either under something that will not move or by having a partner hold them. Your legs should be bent at the knees. Place your hands behind your head and lock them together by clasping your fingers. This is the starting position. Elevate your upper body so that it creates an imaginary V-shape with your thighs. Breathe out when performing this part of the exercise. Once you feel the contraction for a second, lower your upper body back down to the starting position while inhaling. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Sit-Up/0.jpg','exercisedb',true),('Sit_Squats','Sit Squats','cuádriceps',ARRAY['abductores','glúteos','isquiotibiales'],NULL,'stretching',ARRAY['Stand with your feet shoulder width apart. This will be your starting position.','Begin the movement by flexing your knees and hips, sitting back with your hips.','Continue until you have squatted a portion of the way down, but are above parallel, and quickly reverse the motion until you return to the starting position. Repeat for 5-10 repetitions.'],'Stand with your feet shoulder width apart. This will be your starting position. Begin the movement by flexing your knees and hips, sitting back with your hips. Continue until you have squatted a portion of the way down, but are above parallel, and quickly reverse the motion until you return to the starting position. Repeat for 5-10 repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Sit_Squats/0.jpg','exercisedb',true),('Skating','Skating','cuádriceps',ARRAY['abductores','aductores','pantorrillas','glúteos','isquiotibiales'],'otro','cardio',ARRAY['Roller skating is a fun activity which can be effective in improving cardiorespiratory fitness and muscular endurance. It requires relatively good balance and coordination. It is necessary to learn the basics of skating including turning and stopping and to wear protective gear to avoid possible injury.','You can skate at a comfortable pace for 30 minutes straight. If you want a cardio challenge, do interval skating — speed skate two minutes of every five minutes, using the remaining three minutes to recover. A 150 lb person will typically burn about 175 calories in 30 minutes skating at a comfortable pace, similar to brisk walking.'],'Roller skating is a fun activity which can be effective in improving cardiorespiratory fitness and muscular endurance. It requires relatively good balance and coordination. It is necessary to learn the basics of skating including turning and stopping and to wear protective gear to avoid possible injury. You can skate at a comfortable pace for 30 minutes straight. If you want a cardio challenge, do interval skating — speed skate two minutes of every five minutes, using the remaining three minutes to recover. A 150 lb person will typically burn about 175 calories in 30 minutes skating at a comfortable pace, similar to brisk walking.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Skating/0.jpg','exercisedb',true),('Sled_Drag_-_Harness','Sled Drag - Harness','cuádriceps',ARRAY['pantorrillas','glúteos','isquiotibiales'],'otro','strongman',ARRAY['To begin, load the sled with the desired weight and attach the pulling strap. You can pull with handles, use a harness, or attach the pulling strap to a weight belt.','Whether pulling forwards or backwards, lean in the direction of travel and progress by extending through the hips and knees.'],'To begin, load the sled with the desired weight and attach the pulling strap. You can pull with handles, use a harness, or attach the pulling strap to a weight belt. Whether pulling forwards or backwards, lean in the direction of travel and progress by extending through the hips and knees.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Sled_Drag_-_Harness/0.jpg','exercisedb',true);